            $doc.ExportAsFixedFormat($pdf, 17)
            Write-Output "  Saved + PDF re-exported."
        } finally {
            $doc.Close([ref]$false)
        }
    }
} finally {
    if ($word.Documents.Count -eq 0) { $word.Quit() }
    [void][System.Runtime.InteropServices.Marshal]::ReleaseComObject($word)
}
